SELECT SUM(total_hits) AS total_hits
FROM hit_data
WHERE transect_id = 1 AND location_id = 1 AND created_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT DISTINCT u.user_name 
FROM users u
JOIN project_members pm ON u.user_id = pm.user_id;

SELECT pm.project_id, u.user_name, pm.role
FROM project_members pm
JOIN users u ON pm.user_id = u.user_id;

SELECT COUNT(composition_id) AS total_composition
FROM species_composition
WHERE transect_id = 1 AND location_id = 2;

SELECT AVG(total_hits) AS AverageHits
FROM hit_data
WHERE created_date >= 'YYYY-MM-DD';

SELECT permission_id, MAX(updated_date) AS latest_date
FROM project_permissions
GROUP BY permission_id;

SELECT project_id, COUNT(transect_id) AS number_of_transects
FROM project_transepts
GROUP BY project_id;
